         contenu(
            affectop(''/='',l,100),
            declare_constante(
               a,
               divi(
                  mult(
                     s,
                     appelf(element(Math),nomf(min),p(l),p(moins(1,l)))
                  ),
                  100
               )
            ),
            declare_constante(
               f,
               appelf(
                  flechee(),
                  p(n),
                  contenu(
                     declare_constante(
                        k,
                        modulo(plus(n,divi(h,30)),12)
                     ),
                     declare_constante(
                        color,
                        moins(
                           l,
                           mult(
                              a,
                              appelf(
                                 element(Math),
                                 nomf(max),
                                 p(
                                    appelf(
                                       element(Math),
                                       nomf(min),
                                       p(moins(k,3)),
                                       p(moins(9,k)),
                                       p(1)
                                    )
                                 ),
                                 p(-1)
                              )
                           )
                        )
                     ),
                     retourner(
                        appelf(
                           element(
                              appelf(
                                 element(
                                    appelf(element(Math),nomf(round),p(mult(255,color)))
                                 ),
                                 nomf(toString),
                                 p(16)
                              )
                           ),
                           nomf(padStart),
                           p(2),
                           p(''0'')
                        )
                     ),
                     #( convert to Hex and prefix "0" if needed )
                  )
               )
            ),
            retourner(
               concat(
                  "#",
                  appelf(nomf(f),p(0)),
                  "",
                  appelf(nomf(f),p(8)),
                  "",
                  appelf(nomf(f),p(4)),
                  ""
               )
            )
         )
