                              boucle(
                                 initialisation(affecte(i,moins(startPos,2))),
                                 condition(supeg(i,0)),
                                 increment(i--),
                                 faire(
                                    affecte(c,appelf(element(contenu),nomf(substr),p(i),p(1))),
                                    choix(
                                       si(
                                          condition(ou(egalstricte(c,''\n''),egalstricte(c,''\r''))),
                                          alors(break())
                                       )
                                    ),
                                    affecte(ligne_precedente,plus(c,ligne_precedente))
                                 )
                              ),
                              affecte(j,0),
                              boucle(
                                 initialisation(affecte(i,0)),
                                 condition(inf(i,ligne_precedente.length)),
                                 increment(i++),
                                 faire(
                                    affecte(j,i),
                                    choix(
                                       si(
                                          condition(
                                             diffstricte(appelf(element(ligne_precedente),nomf(substr),p(i),p(1)),'' '')
                                          ),
                                          alors(break())
                                       )
                                    ),
                                    choix(
                                       si(
                                          condition(egalstricte(i,moins(ligne_precedente.length,1))),
                                          alors(postinc(j))
                                       )
                                    )
                                 )
                              ),
                              choix(
                                 si(
                                    condition(egalstricte(type_editeur,''rev'')),
                                    alors(
                                       choix(
                                          si(
                                             condition(
                                                egalstricte(
                                                   appelf(element(contenu),nomf(substr),p(moins(startPos,2)),p(1)),
                                                   ''(''
                                                )
                                             ),
                                             alors(
                                                #( 1833 à vérifier ),
                                                affecte(
                                                   a_inserer,
                                                   appelf(element('' ''),nomf(repeat),p(plus(j,3)))
                                                ),
                                                #( NBESPACESREV ),
                                                affectop(''+='',__ig1.position_dans_la_derniere_zone_editee,plus(j,3))
                                             )
                                          ),
                                          sinon(
                                             alors(
                                                affecte(a_inserer,appelf(element('' ''),nomf(repeat),p(j))),
                                                affectop(''+='',__ig1.position_dans_la_derniere_zone_editee,j)
                                             )
                                          )
                                       )
                                    )
                                 ),
                                 sinon(
                                    alors(
                                       choix(
                                          si(
                                             condition(
                                                egalstricte(
                                                   appelf(element(contenu),nomf(substr),p(moins(startPos,2)),p(1)),
                                                   ''{''
                                                )
                                             ),
                                             alors(
                                                affecte(
                                                   a_inserer,
                                                   appelf(element('' ''),nomf(repeat),p(plus(j,4)))
                                                ),
                                                #( NBESPACESSOURCEPRODUIT )
                                             )
                                          ),
                                          sinon(
                                             alors(
                                                affecte(a_inserer,appelf(element('' ''),nomf(repeat),p(j)))
                                             )
                                          )
                                       )
                                    )
                                 )
                              ),
                              declare(
                                 nouveau_contenu,
                                 plus(appelf(element(contenu),nomf(substring),p(0),p(startPos)),a_inserer,appelf(element(contenu),nomf(substring),p(endPos)))
                              ),
                              #( un point virgule est-il en trop ? ),
                              affecte(zoneSource.value,nouveau_contenu),
                              affecte(zoneSource.selectionStart,plus(startPos,a_inserer.length)),
                              affecte(zoneSource.selectionEnd,plus(startPos,a_inserer.length))
                           )
                        )
                     )
                  )
               ),
               sinonsi(
                  condition(et(egal(e.keyCode,86),egal(e.ctrlKey,true))),
                  alors(
                     #(
                       pour une raison que je ne comprends pas,
                       Google Chrome fait bouger le scroll vertical d''une textarea
                       quand on sélectionne une ligne y compris le retour à la ligne de fin
                       et qu''on la copie sur elle même ... dans certains cas
                       
                     ),
                     #(
                       if(zoneSource.scrollTop !== this.#global_tableau_des_textareas[e.target.id].mon_decallage_haut){
                       zoneSource.scrollTop=this.#global_tableau_des_textareas[e.target.id].mon_decallage_haut;
                       }
                     )
                  )
               )
            )
         )
      ),
