      méthode(
         definition(nom(quand_click),argument(e)),
         contenu(
            essayer(
               faire(appelf(element(e),nomf(stopPropagation),p())),
               sierreur(null(),faire())
            ),
            declare_variable(elt,e.target),
            declare_variable(action_rev,appelf(element(elt),nomf(getAttribute),p(''data-rev_click''))),
            faire_tant_que(
               instructions(
                  choix(
                     si(
                        condition(egalstricte(action_rev,null)),
                        alors(
                           affecte(elt,elt.parentNode),
                           affecte(action_rev,appelf(element(elt),nomf(getAttribute),p(''data-rev_click'')))
                        )
                     )
                  )
               ),
               condition(egalstricte(action_rev,null))
            ),
            choix(
               si(
                  condition(ou(egalstricte(action_rev,null),egalstricte(action_rev,''''))),
                  alors(
                     appelf(
                        element(this),
                        nomf(ajoute_message),
                        p(
                           obj(
                              ("__xst",__xer),
                              (
                                 "__xme",
                                 concat(''l\''action_rev n\''est pas définie '',appelf(element(this),nomf(nl2),p()))
                              )
                           )
                        )
                     ),
                     appelf(element(this),nomf(affiche_les_messages),p()),
                     retourner(obj(("__xst",__xer)))
                  )
               )
            ),
            declare_variable(source,concat(action_rev,'''')),
            declare_variable(obj1,appelf(element(this.__rev1),nomf(rev_tcm),p(source))),
            choix(
               si(
                  condition(diffstricte(obj1.__xst,__xsu)),
                  alors(
                     appelf(
                        element(this),
                        nomf(ajoute_message),
                        p(
                           obj(
                              ("__xst",__xer),
                              (
                                 "__xme",
                                 concat(
                                    ''erreur de convertion de source en matrice sur le click <br /><br /><b>'',
                                    source,
                                    ''</b><br /><br />'',
                                    appelf(element(this),nomf(nl2),p()),
                                    ''<br />'',
                                    obj1.__xme
                                 )
                              )
                           )
                        )
                     ),
                     appelf(element(this),nomf(affiche_les_messages),p()),
                     appelf(element(__ig1),nomf(fermer_la_sous_fenetre),p()),
                     retourner(obj(("__xst",__xer)))
                  )
               )
            ),
            appelf(element(elt.classList),nomf(add),p(''yy_invisible'')),
            choix(
               si(
                  condition(sup(this.#liste_des_appels_au_serveur.length,0)),
                  alors(
                     appelf(
                        element(this),
                        nomf(ajoute_message),
                        p(obj(("__xst",__xer),("__xme",''Un appel au serveur est déjà en cours'')))
                     ),
                     appelf(element(this),nomf(affiche_les_messages),p()),
                     retourner(obj(("__xst",__xer)))
                  )
               )
            ),
            appelf(element(this.#boutons_masques_avant_appel),nomf(push),p(elt)),
            declare_variable(mat,obj1.__xva),
            declare_variable(
               obj,
               appelf(
                  element(this),
                  nomf(__xac),
                  p(mat),
                  p(0),
                  p(null),
                  p(e)
               )
            ),
            choix(
               si(
                  condition(egalstricte(obj.__xst,__xer)),
                  alors(
                     appelf(
                        element(this),
                        nomf(ajoute_message),
                        p(
                           obj(
                              ("__xst",__xer),
                              (
                                 "__xme",
                                 concat(''le source de quand_clic :<br /><b>'',source,''</b><br /> ne provoque pas d\''action fo1() , pm1() ou m1()'',appelf(element(this),nomf(nl2),p()))
                              )
                           )
                        )
                     ),
                     appelf(element(this),nomf(affiche_les_messages),p()),
                     appelf(element(this),nomf(retablir_les_boutons_masques),p()),
                     retourner(obj(("__xst",__xer)))
                  )
               )
            ),
            retourner(obj(("__xst",__xsu)))
         )
      ),
