            declare_variable(lst,appelf(element(document),nomf(querySelectorAll),p("[data-rev_menu]"))),
            boucle(
               initialisation(declare_variable(i,0)),
               condition(inf(i,lst.length)),
               increment(i++),
               faire(
                  choix(
                     si(
                        condition(
                           non(appelf(element(lst[i]),nomf(getAttribute),p(''data-rev_event'')))
                        ),
                        alors(appelf(element(lst[i]),nomf(setAttribute),p("data-rev_event"),p("1")),appelf(element(this),nomf(traite_menu),p(lst[i])))
