                           ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p("input"),
                              p(appelf(element(this.#quand_change_ou_entree),nomf(bind),p(this)))
                           ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p("touchend"),
                              p(appelf(element(this.#quand_change_ou_entree),nomf(bind),p(this)))
                           ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p("keyup"),
                              p(appelf(element(this.#quand_change_ou_entree),nomf(bind),p(this)))
                           ),
                           appelf(element(lst[i]),nomf(setAttribute),p("data-rev_event_change_ou_entree"),p("1"))
                        )
                     )
                  )
               )
            ),
            affecte(lst,appelf(element(document),nomf(querySelectorAll),p("[data-rev_change]"))),
            boucle(
               initialisation(declare_variable(i,0)),
               condition(inf(i,lst.length)),
               increment(i++),
               faire(
                  choix(
                     si(
                        condition(
                           non(appelf(element(lst[i]),nomf(getAttribute),p(''data-rev_event_change'')))
                        ),
                        alors(
                           appelf(
                              element(lst[i]),
