                              p(appelf(element(this.quand_change),nomf(bind),p(this)))
                           ),
                           appelf(element(lst[i]),nomf(setAttribute),p("data-rev_event_change"),p("1"))
                        )
                     )
                  )
               )
            ),
            affecte(lst,appelf(element(document),nomf(querySelectorAll),p("[data-editeur1]"))),
            boucle(
               initialisation(declare_variable(i,0)),
               condition(inf(i,lst.length)),
               increment(i++),
               faire(
                  choix(
                     si(
                        condition(
                           non(appelf(element(lst[i]),nomf(getAttribute),p(''data-rev_event'')))
                        ),
                        alors(
                           #( lst[i].addEventListener( ''keydown'' , this.#keydown_sur_editeur1.bind( this ) ); ),
                           #( blur=lost focus ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p(''blur''),
                              p(appelf(element(this.#blur_sur_editeur1),nomf(bind),p(this)))
                           ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p(''mouseup''),
                              p(appelf(element(this.#mouse_up_sur_editeur1),nomf(bind),p(this)))
                           ),
                           appelf(
                              element(lst[i]),
                              nomf(addEventListener),
                              p(''keyup''),
                              p(appelf(element(this.#analyse_key_up_editeur1),nomf(bind),p(this)))
