                              affecte(a1.style.visibility,''visible''),
                              declare_variable(vv_supprimer_les_messages,appelf(element(document),nomf(createElement),p(''div''))),
                              appelf(element(vv_supprimer_les_messages),nomf(setAttribute),p(''id''),p("vv_supprimer_les_messages")),
                              appelf(element(vv_supprimer_les_messages),nomf(setAttribute),p(''class''),p("yy__1")),
                              affecte(vv_supprimer_les_messages.style.position,''sticky''),
                              affecte(vv_supprimer_les_messages.style.top,''0''),
                              declare_variable(t,''''),
                              affectop(''+='',t,''<div class="rev_bouton yy__2 " data-rev_click="m1(n1(__ig1),f1(supprimer_les_messages()))">Supprimer les messages</div>''),
                              choix(
                                 si(
                                    condition(egalstricte(dans_sous_fenetre,false)),
                                    alors(affectop(''+='',t,concat(''<div style="min-width:2.5em;" class="rev_bouton yy__1" data-rev_click="m1(n1(__ig1),f1(agrandir_la_zone_message()))" title="agrandir/retrécir la zone messages">'',this.les_svg.agrandir,this.les_svg.retrecir,''</div>'')),affectop(''+='',t,concat(''<div class="rev_b_svg yy__3" style="transform: translate(0, 3px);" data-rev_click="m1(n1(__ig1),f1(masquer_la_zone_message()))" title="masquer la zone messages">'',this.les_svg.masquer,''</div>'')))
                                 )
                              ),
                              affecte(vv_supprimer_les_messages.innerHTML,t),
                              appelf(element(a1),nomf(insertBefore),p(vv_supprimer_les_messages),p(a1.firstChild)),
                              boucle(
                                 initialisation(declare_variable(i,0)),
                                 condition(inf(i,cumul.length)),
                                 increment(i++),
                                 faire(
                                    declare_variable(div1,appelf(element(document),nomf(createElement),p(''div''))),
                                    affecte(div1.className,concat(''yy__'',cumul[i][0])),
                                    affecte(div1.innerHTML,cumul[i][1]),
                                    appelf(element(a1),nomf(appendChild),p(div1))
                                 )
                              )
                           )
                        )
                     )
                  )
               ),
               sinon(
                  alors(
                     declare_variable(vv_supprimer_les_messages,appelf(element(document),nomf(createElement),p(''div''))),
                     appelf(element(vv_supprimer_les_messages),nomf(setAttribute),p(''id''),p("vv_supprimer_les_messages")),
                     appelf(element(vv_supprimer_les_messages),nomf(setAttribute),p(''class''),p("yy__1")),
                     affecte(vv_supprimer_les_messages.style.position,''sticky''),
                     affecte(vv_supprimer_les_messages.style.top,''0''),
                     declare_variable(t,''''),
                     affectop(''+='',t,''<div class="rev_bouton yy__2 " data-rev_click="m1(n1(__ig1),f1(supprimer_les_messages()))">Supprimer les messages</div>''),
                     choix(
                        si(
                           condition(egalstricte(dans_sous_fenetre,false)),
                           alors(affectop(''+='',t,concat(''<div style="min-width:2.5em;" class="rev_bouton yy__1" data-rev_click="m1(n1(__ig1),f1(agrandir_la_zone_message()))" title="agrandir/retrécir la zone messages">'',this.les_svg.agrandir,this.les_svg.retrecir,''</div>'')),affectop(''+='',t,concat(''<div class="rev_b_svg yy__3" style="transform: translate(0, 3px);" data-rev_click="m1(n1(__ig1),f1(masquer_la_zone_message()))" title="masquer la zone messages">'',this.les_svg.masquer,''</div>'')))
                        )
                     ),
                     affecte(vv_supprimer_les_messages.innerHTML,t),
                     appelf(element(a1),nomf(insertBefore),p(vv_supprimer_les_messages),p(a1.firstChild)),
                     appelf(element(this),nomf(ajoute_les_evenements_aux_boutons),p()),
                     choix(
                        si(
                           condition(egalstricte(dans_sous_fenetre,true)),
                           alors(
                              choix(
                                 si(
                                    condition(
                                       ou(
                                          supeg(appelf(element(a1.innerHTML),nomf(indexOf),p(''class="yy__0"'')),0),
                                          supeg(appelf(element(a1.innerHTML),nomf(indexOf),p(''class="yy__2"'')),0)
                                       )
                                    ),
                                    alors(
                                       essayer(
                                          faire(
                                             appelf(
                                                element(appelf(element(document),nomf(getElementById),p(''vv_sous_fenetre1''))),
                                                nomf(scrollTo),
                                                p(obj(("top",0),("left",0),("behavior","smooth")))
                                             )
                                          ),
                                          sierreur(null(),faire())
                                       )
                                    )
                                 )
                              )
                           )
                        )
                     )
                  )
               )
            ),
            essayer(
               faire(affecte(a1.style.visibility,''visible''),appelf(element(this),nomf(ajoute_les_evenements_aux_boutons),p())),
               sierreur(e2,faire())
            ),
            choix(
               si(
                  condition(egalstricte(this.#timeout_de_dispatition_de_message,null)),
                  alors(
                     affecte(
