                           nomf(setTimeout),
                           p(appelf(element(this.#faire_disparaitre_les_messages_OK),nomf(bind),p(this))),
                           p(1000)
                        )
                     )
                  )
               )
            ),
            retourner(obj(("__xst",__xsu)))
         )
      ),
