      méthode(
         definition(nom(supprime_l_exposant),argument(num)),
         contenu(
            choix(
               si(
                  condition(ou(egalstricte(num,null),egalstricte(num,undefined),egalstricte(num,''''))),
                  alors(
                     throw(
                        new(appelf(nomf(Error),p("Invalid input: value is null, undefined, or empty.")))
                     )
                  )
               )
            ),
            #( Convert to string to handle both number and string inputs ),
            declare_variable(str,appelf(nomf(String),p(num))),
            #( If it''s not in exponential notation, return as is ),
            choix(
               si(
                  condition(
                     non(appelf(element(/e/i),nomf(test),p(str)))
                  ),
                  alors(retourner(str))
               )
            ),
            #( Split into coefficient and exponent ),
            declare_constante(
               defTab(p(coeff),p(exp)),
               appelf(
                  element(appelf(element(str),nomf(toLowerCase),p())),
                  nomf(split),
                  p(''e'')
               )
            ),
            declare_constante(exponent,appelf(nomf(parseInt),p(exp),p(10))),
            #( Handle positive exponent ),
            choix(
               si(
                  condition(sup(exponent,0)),
                  alors(
                     declare_variable(
                        defTab(p(intPart),p(fracPart,defaut(''''))),
                        appelf(element(coeff),nomf(split),p(''.''))
                     ),
                     affecte(fracPart,appelf(element(fracPart),nomf(padEnd),p(exponent),p(''0''))),
                     retourner(
                        plus(
                           intPart,
                           appelf(element(fracPart),nomf(slice),p(0),p(exponent)),
                           ou(appelf(element(fracPart),nomf(slice),p(exponent)),'''')
                        )
                     )
                  )
               ),
               sinon(
                  alors(
                     #( Handle negative exponent ),
                     declare_variable(
                        defTab(p(intPart),p(fracPart,defaut(''''))),
                        appelf(element(coeff),nomf(split),p(''.''))
                     ),
                     declare_constante(
                        zeros,
                        appelf(
                           element(''0''),
                           nomf(repeat),
                           p(
                              moins(appelf(element(Math),nomf(abs),p(exponent)),1)
                           )
                        )
                     ),
                     retourner(concat(''0.'',zeros,intPart,fracPart))
                  )
               )
            )
         )
      ),
