            declare_variable(ret,''''),
            choix(
               si(
                  condition(et(false,supeg(this.__deverminage,2))),
                  alors(
                     appelf(element(console),nomf(log),p(concat(''en entree : input='',input))),
                     affecte(ret,appelf(element(input),nomf(normalize),p("NFD"))),
                     appelf(element(console),nomf(log),p(concat(''ret normalize : ret='',ret))),
                     affecte(ret,appelf(element(ret),nomf(replace),p(/[\u0300-\u036f]/g),p(""))),
                     appelf(element(console),nomf(log),p(concat(''ret replace1 : ret='',ret))),
                     affecte(ret,appelf(element(ret),nomf(replace),p(/[^\x00-\x7F]/g),p(" "))),
                     appelf(element(console),nomf(log),p(concat(''ret replace2 : ret='',ret))),
                     affecte(ret,appelf(element(ret),nomf(replace),p(/[^a-zA-Z0-9]+/g),p('' ''))),
                     affecte(ret,appelf(element(ret),nomf(trim),p())),
                     appelf(element(console),nomf(log),p(concat(''ret final : ret="'',ret,''"'')))
                  )
               ),
               sinon(
                  alors(
                     affecte(
                        ret,
                        appelf(
                           element(
                              appelf(
                                 element(
                                    appelf(
                                       element(
                                          appelf(
                                             element(appelf(element(input),nomf(normalize),p("NFD"))),
                                             nomf(replace),
                                             p(/[\u0300-\u036f]/g),
                                             p("")
                                          )
                                       ),
                                       nomf(replace),
