    /*
      =============================================================================================================
    */
    __xac( mat , d , données , evenement=null ){
        if(!Array.isArray( mat )){
            this.ajoute_message( {"__xst" : __xer ,"__xme" : ''oops, on n\''a pas reçu une matrice dans __ig1.__xac() '' + this.nl2()} );
            this.affiche_les_messages();
            return({"__xst" : __xer});
        }
        let comptage_action=0;
        let l01=mat.length;
        for( let i=d + 1 ; i < l01 ; i=mat[i][12] ){
            if(mat[i][1] === ''fo1'' && mat[i][8] > 0){
                comptage_action++;
                if(données === null){
                    /*
                      formulaire à envoyer, il doit y avoir un co1 [ nom du conteneur contenant les champs input/texterea...
                    */
                    let co1='''';
                    let fo1={};
                    let nombre_de_valeurs_a_envoyer=0;
                    let contient_des_fichier_a_televerser=false;
                    let sur_table_virtuelle=false;
                    for( let j=i + 1 ; j < l01 ; j=mat[j][12] ){
                        if(mat[j][1] === ''sur_table_virtuelle'' && mat[j][2] === ''f''){
                            sur_table_virtuelle=true;
                            break;
                        }
                    }
                    for( let j=i + 1 ; j < l01 ; j=mat[j][12] ){
                        if(mat[j][1] === ''co1'' && mat[j][2] === ''f'' && mat[j][8] === 1 && mat[j + 1][2] === ''c''){
                            co1=mat[j + 1][1];
                            let t1=document.getElementById( co1 );
                            if(t1 === null){
                                this.ajoute_message( {"__xst" : __xer ,"__xme" : '' l\''id '' + co1 + '' n\''a pas été trouvé dans la page'' + this.nl2()} );
                                this.affiche_les_messages();
                                return({"__xst" : __xer});
                            }
                            fo1[co1]={};
                            let lst=t1.getElementsByTagName( ''*'' );
                            for( let k=0 ; k < lst.length ; k++ ){
                                if(lst[k].value !== null && lst[k].id){
                                    if(lst[k].type && lst[k].type.toLowerCase() === ''checkbox''){
                                        fo1[co1][lst[k].id]=lst[k].checked;
                                        nombre_de_valeurs_a_envoyer++;
                                    }else if(lst[k].type && lst[k].type.toLowerCase() === ''file''){
                                        /*
                                          le téléversement de fichiers se passe ailleurs
                                        */
                                        contient_des_fichier_a_televerser=true;
                                    }else{
                                        if(sur_table_virtuelle === true){
                                            fo1[co1][lst[k].id]=this.utf8ToAscii( lst[k].value );
                                        }else{
                                            fo1[co1][lst[k].id]=lst[k].value;
                                        }
                                        nombre_de_valeurs_a_envoyer++;
                                    }
                                }
                            }
                        }
                    }
                    if(co1 === ''''){
                        this.ajoute_message( {"__xst" : __xer ,"__xme" : ''il manque le nom du formulaire co1(xxx) '' + this.nl2()} );
                        this.affiche_les_messages();
                        return({"__xst" : __xer});
                    }
                    for( let j=i + 1 ; j < l01 ; j=mat[j][12] ){
                        if(mat[j][1] === ''pm1'' && mat[j][2] === ''f''){
                            /*
                              après un formulaire on peut faire un post-message ...
                            */
                            let re_source=this.__rev1.matrice_vers_source_rev1( mat , j , false , j + 1 );
                            if(re_source.__xst !== __xsu){
                                this.ajoute_message( {"__xst" : __xer ,"__xme" : ''Erreur de convertion de matrice en source '' + this.nl2()} );
                                this.affiche_les_messages();
                                return({"__xst" : __xer});
                                /* source=re_source.__xva; */
                            }
                            if(contient_des_fichier_a_televerser === true){
                            }else{
                                this.envoyer_un_message_au_worker( {"__xac" : ''pm1('' + re_source.__xva + '')'' ,"__xva" : {"__fo1" : fo1 ,"__co1" : co1}} );
                            }
                        }else if(mat[j][1] === ''m1'' && mat[j][2] === ''f''){
                            /*
                              ... ou bien appeler un module, par exemple pour la vérification du formulaire avant envoie
                            */
                            let re_source=this.__rev1.matrice_vers_source_rev1( mat , j , false , j + 1 );
                            let cmd1=''m1('' + re_source.__xva + '')'';
                            this.executer1( cmd1 , {"__fo1" : fo1 ,"__co1" : co1} , evenement );
                        }else if(mat[j][1] === ''co1'' && mat[j][2] === ''f''){
                        }else if(mat[j][1] === ''sur_table_virtuelle'' && mat[j][2] === ''f''){
                        }else{
                            debugger;
                        }
                    }
                }else{
                    debugger;
                }
            }else if(mat[i][1] === ''pm1'' && mat[i][8] > 0){
                comptage_action++;
                if(données === null){
                    let re_source=this.__rev1.matrice_vers_source_rev1( mat , i , false , i + 1 );
                    if(re_source.__xst !== __xsu){
                        this.ajoute_message( {"__xst" : __xer ,"__xme" : ''Erreur de convertion de matrice en source '' + this.nl2()} );
                        this.affiche_les_messages();
                        return({"__xst" : __xer});
                        /* source=re_source.__xva; */
                    }
                    this.envoyer_un_message_au_worker( {"__xac" : ''pm1('' + re_source.__xva + '')'' ,"__xva" : {}} );
                }else{
                    if(i > 1 && données.__xva.hasOwnProperty( ''redirection'' ) && données.__xva.redirection !== ''''){
                        this.envoyer_un_message_au_worker( {"__xac" : données.__xva.redirection ,"__xva" : {}} );
                    }else{
                        this.__xac( mat , i , données );
                    }
                }
            }else if(mat[i][1] === ''m1'' && mat[i][8] > 0){
                comptage_action++;
                let n1='''';
                let indice=-1;
                for( let j=i + 1 ; j < l01 ; j=mat[j][12] ){
                    if(mat[j][1] === ''n1'' && mat[j][8] === 1){
                        n1=mat[j + 1][1];
                    }else if(mat[j][1] === ''f1'' && mat[j][2] === ''f''){
                        indice=j;
                    }
                }
                if(n1 !== '''' && indice > 0){
                    let ret1=this.m1( n1 , mat , indice , données , evenement );
                }else{
                    debugger;
                    let re_source=this.__rev1.matrice_vers_source_rev1( mat , 0 , true , 1 );
                    this.ajoute_message( {"__xst" : __xer ,"__xme" : ''<b>n1 vide ou f1 non trouvé dans :</b><br /><pre>'' + re_source.__xva + ''</pre> <br />'' + this.nl2()} );
                    this.affiche_les_messages();
                    return({"__xst" : __xer});
                }
            }else if(mat[i][1] === ''confirmer1'' && mat[i][8] > 0){
                comptage_action++;
                if(window.confirm( ''certain ?'' )){
                    this.__xac( mat , i , données );
                }else{
                    this.retablir_les_boutons_masques( données );
                }
            }else{
                this.ajoute_message( {"__xst" : __xer ,"__xme" : ''<b>l\''action "'' + mat[i][1] + ''" n\''est pas prévue</b> '' + this.nl2()} );
            }
        }
        if(comptage_action === 0){
            return({"__xst" : __xer});
        }
        return({"__xst" : __xsu});
    }
