    aller_a_la_page( mat , d , nom_de_module , fonction_liste , filtres , ref_zone=null , num_page=null , est_table_virtuelle=false , de_13='''' ){
        let nom_de_zone='''';
        if(ref_zone !== null){
            nom_de_zone=ref_zone;
        }else{
            let l01=mat.length;
            let __num_page=-1;
            for( let i=d + 1 ; i < l01 ; i=mat[i][12] ){
                if(mat[i][2] === ''c''){
                    nom_de_zone=mat[i][1];
                }
            }
        }
        if(nom_de_zone !== ''''){
            let __num_page=-1;
            if(ref_zone !== null){
                if(isNaN( num_page )){
                    try{
                        __num_page=parseInt( document.getElementById( ref_zone ).value , 10 );
                    }catch{
                        __num_page=0;
                    }
                }else{
                    __num_page=num_page;
                }
            }else{
                __num_page=parseInt( document.getElementById( nom_de_zone ).getAttribute( ''data-numero_page'' ) , 10 );
            }
            if(__num_page >= 0){
                document.getElementById( ''__num_page'' ).value=__num_page;
                let lst=document.getElementById( fonction_liste ).querySelectorAll( "input" );
                filtres[fonction_liste]={};
                for( let i=0 ; i < lst.length ; i++ ){
                    if(lst[i].id){
                        if(lst[i].value === ''''){
                        }else{
                            if(est_table_virtuelle === true){
                                filtres[fonction_liste][lst[i].id]=this.utf8ToAscii( lst[i].value );
                                if(filtres[fonction_liste][lst[i].id].indexOf( ''%'' ) >= 0){
                                    debugger;
                                }
                            }else{
                                filtres[fonction_liste][lst[i].id]=lst[i].value;
                            }
                        }
                    }
                }
                let __fo1={};
                __fo1[fonction_liste]=filtres[fonction_liste];
                let option_de_13='''';
                if(de_13 !== ''''){
                    option_de_13=''de_13('' + de_13 + '')'';
                }
                this.envoyer_un_message_au_worker( {
                        "__xac" : ''pm1(m1(n1('' + nom_de_module + ''),f1('' + fonction_liste + ''('' + option_de_13 + ''))))'' ,
                        "__xva" : {"__fo1" : __fo1 ,"__co1" : fonction_liste}
                    } );
            }else{
                if(ref_zone == null){
                    setTimeout( ( a ) => {
                            (document.getElementById( a.nom_de_zone ).classList).remove( ''yy_invisible'' );} , 100 , {"nom_de_zone" : nom_de_zone} );
                }
            }
        }
        return({"__xst" : __xsu});
    }
