                this.affiche_les_messages();
                return({"__xst" : __xer});
            }
        }else{
            console.log( ''Aucune action pour la matrice\n'' , ''background:yellow;color:yellow;'' , mat );
            /*
              debugger
              this.ajoute_message({ __xst : __xer, __xme : ''Erreur de mise à jour du contenu '' + this.nl2()});
              this.affiche_les_messages();
              return {__xst:__xer};
            */
        }
        return({"__xst" : __xsu});
